352→        schemaLinter,
353→        sduiAutocompletion(),
354→        themeCompartment.of(initialTheme),
355→        updateListener,
356→        keymap.of([
357→          {
358→            key: 'Mod-k',
359→            run: () => {
360→              onSnippetRequestRef.current?.();
361→              return true;
362→            },
363→          },
364→          {
