  7→import { knownTypes, componentPropsSchemas } from './sduiSchema';
  8→
  9→interface PropSchema {
 10→  type: string;
 11→  properties?: Record<string, PropDef>;
 12→  required?: readonly string[];
 13→  enum?: readonly string[];
 14→  nullable?: boolean;
 15→}
 16→
 17→interface PropDef {
 18→  type?: string;
 19→  enum?: readonly string[];
 20→  nullable?: boolean;
 21→  const?: string;
 22→  items?: object;
 23→}
 24→
 25→const spacingValues = [
 26→  'none', 'xxxs', 'xxs', 'xs', 'smaller', 'sm', 'md', 'lg', 'xl', 'xxl', 'xxxl',
 27→];
 28→
 29→const screenTopLevelKeys = ['id', 'context', 'header', 'body', 'footer'];
 30→
