 32→
 33→function getTypeDescription(type: string): string {
 34→  const descriptions: Record<string, string> = {
 35→    heading: 'Large title text (headingMDL)',
 36→    text: 'Configurable text with type/color/bold',
 37→    section_heading: 'Section subtitle (subtitleXXL)',
 38→    balance_display: 'Points balance with label and values',
 39→    points_input: 'Numeric input field for points/reais',
 40→    button: 'CTA button with text and optional icon',
 41→    link: 'Pressable text link',
 42→    alert: 'Info/warning/error alert box',
 43→    list_text_icon: 'List of items with icon + description',
 44→    separator: 'Horizontal line divider',
 45→    icon_text_row: 'Row with icon and text side-by-side',
 46→    nav_header: 'Navigation header with back button',
 47→    rich_text: 'Inline formatted text with bold/link/icon nodes',
 48→    points_card: 'Points balance card (CardPoints)',
 49→    tab_bar: 'Horizontal tab navigation bar',
 50→    transaction_item: 'Transaction row with icon/title/value',
 51→    date_separator: 'Date section header label',
 52→  };
 53→  return descriptions[type] ?? type;
 54→}
 55→
 56→function getPropDetail(_propName: string, propDef: PropDef): string {
 57→  if (propDef.enum) return `enum: ${propDef.enum.join(' | ')}`;
 58→  if (propDef.type === 'boolean') return 'boolean';
 59→  if (propDef.type === 'number') return 'number';
 60→  if (propDef.type === 'string') return 'string';
 61→  if (propDef.type === 'array') return 'array';
 62→  if (propDef.type === 'object') return 'object';
 63→  return '';
 64→}
 65→
 66→function isInsideStringLiteral(doc: string, pos: number): boolean {
 67→  let inString = false;
 68→  let stringChar = '';
 69→
 70→  for (let i = 0; i < pos; i++) {
 71→    const ch = doc[i];
 72→    if (inString) {
 73→      if (ch === '\\') { i++; continue; }
 74→      if (ch === stringChar) inString = false;
 75→    } else if (ch === '"' || ch === "'") {
 76→      inString = true;
 77→      stringChar = ch;
 78→    }
 79→  }
 80→  return inString;
 81→}
 82→
 83→function sduiCompletionSource(context: CompletionContext): CompletionResult | null {
 84→  const doc = context.state.doc.toString();
 85→  const pos = context.pos;
 86→
 87→  if (!context.explicit) {
 88→    const charBefore = pos > 0 ? doc[pos - 1] : '';
 89→    if (charBefore && /[{}[\]:,\s]/.test(charBefore)) {
 90→      return null;
 91→    }
 92→  }
 93→
 94→  const beforeChar = doc.slice(Math.max(0, pos - 80), pos);
 95→
 96→  const typeValueMatch = beforeChar.match(/"type"\s*:\s*"([^"]*)$/);
 97→  if (typeValueMatch) {
 98→    const prefix = typeValueMatch[1];
 99→    const from = pos - prefix.length;
100→    const options: Completion[] = (knownTypes as readonly string[]).map(t => ({
101→      label: t,
102→      type: 'enum',
103→      detail: getTypeDescription(t),
104→      boost: t.startsWith(prefix) ? 2 : 0,
105→    }));
106→    return { from, options, filter: true };
107→  }
108→
109→  const spacingValueMatch = beforeChar.match(
110→    /"(?:mt|mb|ml|mr)"\s*:\s*"([^"]*)$/
111→  );
112→  if (spacingValueMatch) {
113→    const prefix = spacingValueMatch[1];
114→    const from = pos - prefix.length;
115→    const options: Completion[] = spacingValues.map(v => ({
116→      label: v,
117→      type: 'enum',
118→      detail: 'spacing token',
119→    }));
120→    return { from, options, filter: true };
121→  }
122→
123→  const propValueMatch = beforeChar.match(/"(\w+)"\s*:\s*"([^"]*)$/);
124→  if (propValueMatch) {
125→    const propName = propValueMatch[1];
126→    const prefix = propValueMatch[2];
127→    const from = pos - prefix.length;
128→
129→    if (['mt', 'mb', 'ml', 'mr'].includes(propName)) {
130→      return {
131→        from,
132→        options: spacingValues.map(v => ({
133→          label: v,
134→          type: 'enum' as const,
135→          detail: 'spacing token',
136→        })),
137→        filter: true,
138→      };
139→    }
140→
141→    if (propName === 'align') {
142→      return {
143→        from,
144→        options: ['left', 'center', 'right'].map(v => ({
145→          label: v,
146→          type: 'enum' as const,
147→          detail: 'text alignment',
148→        })),
149→        filter: true,
150→      };
151→    }
152→
153→    if (propName === 'keyboardType') {
154→      return {
155→        from,
156→        options: ['numeric', 'default', 'email-address', 'phone-pad'].map(v => ({
157→          label: v,
158→          type: 'enum' as const,
159→          detail: 'keyboard type',
160→        })),
161→        filter: true,
162→      };
163→    }
164→  }
165→
166→  if (isInsideStringLiteral(doc, pos)) return null;
167→
168→  if (isInsidePropsObject(doc, pos)) {
169→    const componentType = getComponentTypeForPropsAt(doc, pos);
170→    if (componentType) {
171→      const schema = componentPropsSchemas[componentType] as PropSchema | undefined;
172→      if (schema?.properties) {
173→        const word = context.matchBefore(/[\w"]+/);
174→        if (!word && !context.explicit) return null;
175→        const from = word?.from ?? pos;
176→        const existingKeys = getExistingKeysInObject(doc, pos);
177→        const required = (schema.required as readonly string[] | undefined) ?? [];
178→
179→        const options: Completion[] = Object.entries(schema.properties)
180→          .filter(([key]) => !existingKeys.has(key))
181→          .map(([key, def]) => {
182→            const isRequired = required.includes(key);
183→            const detail = getPropDetail(key, def as PropDef);
184→            return {
185→              label: `"${key}"`,
186→              displayLabel: key,
187→              type: isRequired ? 'property' : 'variable',
188→              detail: `${detail}${isRequired ? ' (required)' : ''}`,
189→              boost: isRequired ? 10 : 0,
190→              apply: buildPropApply(key, def as PropDef),
191→            };
192→          });
193→
194→        if (options.length === 0) return null;
195→        return { from, options, filter: true };
196→      }
197→    }
198→  }
199→
200→  if (isInsideComponentObject(doc, pos)) {
201→    const word = context.matchBefore(/[\w"]+/);
