203→    const from = word?.from ?? pos;
204→    const existingKeys = getExistingKeysInObject(doc, pos);
205→
206→    const options: Completion[] = componentStructureKeys
207→      .filter(key => !existingKeys.has(key))
208→      .map(key => {
209→        const detail = key === 'type' ? 'component type (required)'
210→          : key === 'props' ? 'component properties (required)'
211→          : 'conditional visibility';
212→        return {
213→          label: `"${key}"`,
214→          displayLabel: key,
215→          type: 'property',
216→          detail,
217→          boost: key === 'type' ? 10 : key === 'props' ? 9 : 0,
218→          apply: key === 'type' ? '"type": ""'
219→            : key === 'props' ? '"props": {}'
220→            : '"visible": { "rule": {} }',
