222→      });
223→
224→    if (options.length === 0) return null;
225→    return { from, options, filter: true };
226→  }
227→
228→  if (isInsideTopLevelObject(doc, pos)) {
229→    const word = context.matchBefore(/[\w"]+/);
230→    if (!word && !context.explicit) return null;
231→    const from = word?.from ?? pos;
232→    const existingKeys = getExistingKeysInObject(doc, pos);
233→
234→    const options: Completion[] = screenTopLevelKeys
235→      .filter(key => !existingKeys.has(key))
236→      .map(key => ({
237→        label: `"${key}"`,
238→        displayLabel: key,
239→        type: 'property',
240→        detail: key === 'id' ? 'screen identifier (required)'
241→          : key === 'body' ? 'component list (required)'
242→          : key === 'context' ? 'interpolation data'
243→          : key === 'header' ? 'screen header component'
244→          : 'screen footer component',
245→        boost: key === 'id' ? 10 : key === 'body' ? 9 : 0,
246→        apply: key === 'id' ? '"id": ""'
247→          : key === 'body' ? '"body": []'
248→          : key === 'context' ? '"context": {}'
249→          : key === 'header' ? '"header": { "type": "", "props": {} }'
250→          : '"footer": { "type": "", "props": {} }',
251→      }));
252→
253→    if (options.length === 0) return null;
254→    return { from, options, filter: true };
255→  }
