260→function buildPropApply(key: string, def: PropDef): string {
261→  if (def.type === 'boolean') return `"${key}": false`;
262→  if (def.type === 'number') return `"${key}": 0`;
263→  if (def.type === 'array') return `"${key}": []`;
264→  if (def.type === 'object') return `"${key}": {}`;
265→  return `"${key}": ""`;
266→}
