268→function isInsidePropsObject(doc: string, pos: number): boolean {
269→  const before = doc.slice(0, pos);
270→  let depth = 0;
271→  let inStr = false;
272→  let strCh = '';
273→
274→  for (let i = before.length - 1; i >= 0; i--) {
275→    const ch = before[i];
276→
277→    if (inStr) {
278→      if (ch === strCh && (i === 0 || before[i - 1] !== '\\')) inStr = false;
279→      continue;
280→    }
281→    if (ch === '"' || ch === "'") { inStr = true; strCh = ch; continue; }
282→
283→    if (ch === '}') depth++;
284→    if (ch === '{') {
285→      depth--;
286→      if (depth < 0) {
287→        const preceding = before.slice(Math.max(0, i - 30), i).trim();
288→        return /["']props["']\s*:\s*$/.test(preceding);
289→      }
290→    }
291→  }
292→  return false;
293→}
