295→function getComponentTypeForPropsAt(doc: string, pos: number): string | null {
296→  const before = doc.slice(0, pos);
297→  let depth = 0;
298→
299→  for (let i = before.length - 1; i >= 0; i--) {
300→    if (before[i] === '}') depth++;
301→    if (before[i] === '{') {
302→      depth--;
303→      if (depth < 0) {
304→        const outerStart = before.lastIndexOf('{', i - 1);
305→        if (outerStart >= 0) {
306→          const outerChunk = doc.slice(outerStart, outerStart + 300);
307→          const typeMatch = outerChunk.match(/"type"\s*:\s*"([^"]+)"/);
308→          if (typeMatch?.[1] && (knownTypes as readonly string[]).includes(typeMatch[1])) {
309→            return typeMatch[1];
310→          }
311→        }
312→        break;
313→      }
314→    }
315→  }
316→  return null;
317→}
