319→function isInsideComponentObject(doc: string, pos: number): boolean {
320→  const before = doc.slice(0, pos);
321→  let depth = 0;
322→
323→  for (let i = before.length - 1; i >= 0; i--) {
324→    if (before[i] === '}' || before[i] === ']') depth++;
325→    if (before[i] === '{' || before[i] === '[') {
326→      depth--;
327→      if (depth < 0) {
328→        if (before[i] === '[') {
329→          const preceding = before.slice(Math.max(0, i - 30), i).trim();
330→          return /["']body["']\s*:\s*$/.test(preceding);
331→        }
332→        const preceding = before.slice(Math.max(0, i - 30), i).trim();
333→        if (/,\s*$/.test(preceding) || /\[\s*$/.test(preceding)) {
334→          const bracketSearch = before.slice(0, i);
335→          const bracketPos = bracketSearch.lastIndexOf('[');
336→          if (bracketPos >= 0) {
337→            const beforeBracket = bracketSearch.slice(Math.max(0, bracketPos - 30), bracketPos).trim();
338→            return /["']body["']\s*:\s*$/.test(beforeBracket);
339→          }
340→        }
341→        return false;
342→      }
343→    }
344→  }
345→  return false;
346→}
