348→function isInsideTopLevelObject(doc: string, pos: number): boolean {
349→  const before = doc.slice(0, pos);
350→  let depth = 0;
351→
352→  for (let i = before.length - 1; i >= 0; i--) {
353→    if (before[i] === '}' || before[i] === ']') depth++;
354→    if (before[i] === '{' || before[i] === '[') {
355→      depth--;
356→      if (depth < 0) {
357→        if (before[i] === '{') {
358→          const preceding = before.slice(0, i).trim();
359→          return preceding.length === 0;
360→        }
361→        return false;
362→      }
363→    }
364→  }
365→  return false;
366→}
